void PulseScreenViewBase::buttonCallbackHandler(const touchgfx::AbstractButton& src)
{
    if (&src == &startButton)
    {
        //Interaction1
        //When startButton clicked call virtual function
        //Call startPulse
        startPulse();
    }
    if (&src == &endButton)
    {
        //Interaction2
        //When endButton clicked call virtual function
        //Call endPulse
        endPulse();
    }
    if (&src == &homeButton)
    {
        //Interaction3
        //When homeButton clicked change screen to HomeScreen
        //Go to HomeScreen with no screen transition
        application().gotoHomeScreenScreenNoTransition();
    }
}
